import multiprocessing

def task(arg1, arg2):
    # 执行任务逻辑
    return arg1 + arg2

if __name__ == '__main__':
    processes = []
    for i in range(4):
        p = multiprocessing.Process(target=task, args=(i, i*2))
        processes.append(p)
        p.start()
    for p in processes:
        p.join()
